text:
{
  "formal_minutes": {
    "meeting_info": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": [
        "Minjun",
        "Seoyeon",
        "Doyun",
        "Hara"
      ]
    },
    "decisions": {
      "confirmed_decisions": [
        {
          "topic": "공개 릴리스 목표 시점",
          "decision": "스모크 테스트가 통과할 경우 금요일 15:00 KST를 공개 릴리스 목표 시점으로 둔다."
        },
        {
          "topic": "packageName mismatch 대응",
          "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
        }
      ],
      "rejected_proposals": [
        {
          "topic": "smoke-theme-pack.mjs 처리 방식",
          "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경하자는 제안",
          "result": "거절됨"
        }
      ]
    },
    "non_decisions": {
      "internal_stretch_goals": [
        {
          "topic": "수요일 릴리스",
          "note": "Seoyeon이 제안했으나 확정 일정이 아니며, 내부 스트레치 목표로만 언급되었다."
        }
      ],
      "pending_or_unassigned": [
        {
          "topic": "README 설치 절차 검토",
          "note": "목요일까지 가능하면 검토하자는 의견이 있었으나 담당자는 지정되지 않았다."
        }
      ]
    },
    "risks": [
      {
        "risk": "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README 설치 절차가 오래된 상태면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 failure triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "선행 결과 대기",
      "source_certainty": "확정"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 목요일까지 가능하면 검토한다.",
      "due": "목요일까지 가능하면",
      "status": "담당자 미지정",
      "source_certainty": "부분 확정"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 이후 Minjun의 스모크 테스트 결과를 확인한다.",
      "스모크 결과 공유 후 Hara의 tarball 경로 점검 결과를 확인한다.",
      "금요일 12:00 KST 이후 Doyun의 failure triage note 작성 여부를 확인한다.",
      "README 설치 절차 검토의 담당자 지정 여부와 실제 검토 진행 여부를 확인한다.",
      "최종 릴리스 승인 권한자에 대한 결정 여부를 확인한다.",
      "릴리스 노트에 수요일 내부 스트레치 목표를 언급할지 여부를 확인한다."
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "운영 장애 또는 프로덕션 아웃티지",
      "법무 승인 요건",
      "명시되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "인라인 픽스처에 없는 고객, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "확정되지 않은 사항은 결정으로 기록하지 않는다.",
    "담당자나 마감이 없는 항목에는 임의의 owner나 due를 부여하지 않는다.",
    "수요일 릴리스는 확정 일정이 아니라 내부 스트레치 목표로만 기록한다.",
    "거절된 제안은 확정 결정과 분리해 기록한다.",
    "열린 질문은 답이 정해진 것처럼 서술하지 않는다."
  ]
}
